css:
.loader {
      display: inline-grid;
      grid-template-columns: repeat(2, 17px);
      gap: 8px;
    }
    .loader i {
      width: 17px;
      height: 17px;
      border-radius: 4px;
      background: var(--loader-color);
      animation: gridFlash 1.1400000000000001s ease-in-out infinite;
    }
    .loader i:nth-child(1) { animation-delay: 0.00s; }
.loader i:nth-child(2) { animation-delay: 0.08s; }
.loader i:nth-child(3) { animation-delay: 0.08s; }
.loader i:nth-child(4) { animation-delay: 0.16s; }
    @keyframes gridFlash { 0%, 70%, 100% { opacity: .25; transform: scale(.75); } 35% { opacity: 1; transform: scale(1); } }
